    stateFilter: string;
    regionFilter: string;
    sortBy: SortField;
    sortDir: "asc" | "desc";
    page: number;
    rankSource: RankSource;
  } | null>(null);

  const currentFiltersRef = useRef({
    search,
    stateFilter,
    regionFilter,
    sortBy,
    sortDir,
    page,
    rankSource,
  });
  useEffect(() => {
    currentFiltersRef.current = {
      search,
      stateFilter,
      regionFilter,
      sortBy,
      sortDir,
      page,
      rankSource,
    };
  }, [search, stateFilter, regionFilter, sortBy, sortDir, page, rankSource]);

  const handleRankSourceChange = useCallback(
    (source: RankSource) => {
      const oldField = rankSource === "niche" ? "nicheRanking" : "csRanking";
      const newField = source === "niche" ? "nicheRanking" : "csRanking";
      setRankSource(source);
      if (sortBy === oldField) setSortBy(newField);
      setPage(1);
    },
    [rankSource, sortBy]
