"use client";

import {
  ScatterChart,
  Scatter,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  Label,
} from "recharts";
import type { School } from "@/lib/data/schema";

interface ROIChartProps {
  schools: School[];
}

interface DotEntry {
  name: string;
  x: number;
  y: number;
}

export default function ROIChart({ schools }: ROIChartProps) {
  const data: DotEntry[] = schools
    .filter((s) => s.medianEarnings6yr != null && s.medianEarnings6yr > 0 && s.tuitionInState > 0)
    .slice(0, 20)
    .map((s) => ({
      name: s.name,
      x: s.tuitionInState,
      y: s.medianEarnings6yr as number,
    }));

  if (data.length === 0) {
    return (
      <div className="w-full h-[360px] flex items-center justify-center">
        <div className="text-center text-subtext0">
          <p className="text-lg font-bold text-overlay0 mb-2">No Chart Data</p>
          <p className="text-sm">No data available for chart</p>
        </div>
      </div>
    );
  }

  return (
    <div className="w-full h-[360px]">
      <ResponsiveContainer width="100%" height="100%">
        <ScatterChart margin={{ top: 16, right: 24, left: 16, bottom: 48 }}>
          <CartesianGrid strokeDasharray="3 3" stroke="var(--ctp-surface1)" />
          <XAxis
            type="number"
            dataKey="x"
            name="In-State Tuition"
            tickFormatter={(v) => `$${(v / 1000).toFixed(0)}k`}
            tick={{ fontSize: 11, fill: "var(--ctp-subtext0)" }}
          >
            <Label
              value="In-State Tuition →"
              offset={-8}
              position="insideBottom"
              fill="var(--ctp-subtext0)"
              fontSize={11}
            />
          </XAxis>
          <YAxis
            type="number"
            dataKey="y"
            name="Median Earnings (6yr)"
            tickFormatter={(v) => `$${(v / 1000).toFixed(0)}k`}
            tick={{ fontSize: 11, fill: "var(--ctp-subtext0)" }}
            width={52}
          >
            <Label
              value="Earnings (6yr) →"
              angle={-90}
              position="insideLeft"
              offset={16}
              fill="var(--ctp-subtext0)"
              fontSize={11}
            />
          </YAxis>
          <Tooltip
            content={({ active, payload }) => {
              if (!active || !payload?.length) return null;
              const d = payload[0].payload as DotEntry;
              return (
                <div
                  style={{
                    background: "var(--ctp-mantle)",
                    border: "1px solid var(--ctp-surface0)",
                    borderRadius: 8,
                    padding: "8px 12px",
                    color: "var(--ctp-text)",
                    fontSize: 12,
                    maxWidth: 220,
                  }}
                >
                  <p style={{ fontWeight: 600, marginBottom: 6 }}>{d.name}</p>
                  <p style={{ color: "var(--ctp-peach)" }}>
                    Tuition: ${d.x.toLocaleString()}
                  </p>
                  <p style={{ color: "var(--ctp-green)" }}>
                    Earnings: ${d.y.toLocaleString()}
                  </p>
                </div>
              );
            }}
          />
          <Scatter data={data} fill="var(--ctp-blue)" opacity={0.75} />
        </ScatterChart>
      </ResponsiveContainer>
    </div>
  );
}

"use client";

import { useState, useMemo, useEffect, useCallback, useRef } from "react";
import { useSearchParams } from "next/navigation";
import Link from "next/link";
import dynamic from "next/dynamic";
import type { School } from "@/lib/data/schema";
import { useDebounce } from "@/hooks/useDebounce";
import GradeBadge from "./GradeBadge";
import Pagination from "./Pagination";
import SchoolLogo from "./SchoolLogo";
import { useChatContext } from "./ChatProvider";
import HeartButton from "./HeartButton";
import CompareButton from "./CompareButton";
import Select from "./Select";

const ROIChart = dynamic(() => import("./ROIChart"), { ssr: false });

// Import filtering logic from client-safe filters.ts (NOT loadSchools.ts which uses Node.js fs)
import { filterSchools, calculatePaybackYears, type SortField, type FilterResult } from "@/lib/data/filters";
import { formatCurrency, formatPercent } from "@/utils/format";

interface SchoolListProps {
  csrankingsSchools: School[];
  nicheSchools: School[];
}

interface SortOption {
  value: SortField;
  label: string;
  defaultDir: "asc" | "desc";
}

type RankSource = "csrankings" | "niche";

function getSortOptions(rankSource: RankSource): SortOption[] {
  const rankField: SortField = rankSource === "niche" ? "nicheRanking" : "csRanking";
  return [
    { value: rankField, label: "Ranking", defaultDir: "asc" },
    { value: "roi", label: "ROI", defaultDir: "asc" },
    { value: "earnings", label: "Earnings", defaultDir: "desc" },
    { value: "tuitionInState", label: "Tuition", defaultDir: "asc" },
    { value: "acceptanceRate", label: "Acceptance", defaultDir: "asc" },
    { value: "academics", label: "Academics", defaultDir: "desc" },
    { value: "value", label: "Value", defaultDir: "desc" },
    { value: "campusFood", label: "Food", defaultDir: "desc" },
    { value: "dorms", label: "Dorms", defaultDir: "desc" },
    { value: "safety", label: "Safety", defaultDir: "desc" },
    { value: "diversity", label: "Diversity", defaultDir: "desc" },
    { value: "professors", label: "Professors", defaultDir: "desc" },
    { value: "studentLife", label: "Social", defaultDir: "desc" },
    { value: "partyScene", label: "Party", defaultDir: "desc" },
    { value: "athletics", label: "Athletics", defaultDir: "desc" },
    { value: "location", label: "Location", defaultDir: "desc" },
  ];
}

// All valid sort fields and their default sort direction — used to validate URL params
// including niche grade fields set by the AI (not shown in the UI sort pills)
const ALL_SORT_FIELDS: Record<SortField, "asc" | "desc"> = {
  csRanking: "asc",
  nicheRanking: "asc",
  roi: "asc",
  earnings: "desc",
  tuitionInState: "asc",
  tuitionOutOfState: "asc",
  acceptanceRate: "asc",
  graduationRate: "desc",
  medianDebt: "asc",
  enrollment: "desc",
  campusFood: "desc",
  dorms: "desc",
  safety: "desc",
  partyScene: "desc",
  diversity: "desc",
  studentLife: "desc",
  professors: "desc",
  athletics: "desc",
  value: "desc",
  location: "desc",
  academics: "desc",
};

const PER_PAGE = 10;

export default function SchoolList({ csrankingsSchools, nicheSchools }: SchoolListProps) {
  const searchParams = useSearchParams();

  // Initialize state from URL search params (enables shareable/bookmarkable URLs)
  const [rankSource, setRankSource] = useState<RankSource>(() => {
    const param = searchParams.get("rank");
    return param === "csrankings" ? "csrankings" : "niche";
  });
  const [search, setSearch] = useState(searchParams.get("q") ?? "");
  const [stateFilter, setStateFilter] = useState(searchParams.get("state") ?? "");
  const [regionFilter, setRegionFilter] = useState(searchParams.get("region") ?? "");
  const [sortBy, setSortBy] = useState<SortField>(() => {
    const param = searchParams.get("sort");
    const src = searchParams.get("rank") === "csrankings" ? "csrankings" : "niche";
    const defaultField: SortField = src === "niche" ? "nicheRanking" : "csRanking";
    if (!param || param === "ranking") return defaultField;
    return param in ALL_SORT_FIELDS ? (param as SortField) : defaultField;
  });
  const [sortDir, setSortDir] = useState<"asc" | "desc">(() => {
    const dir = searchParams.get("dir");
    if (dir === "asc" || dir === "desc") return dir;
    const paramSort = searchParams.get("sort");
    if (paramSort && paramSort in ALL_SORT_FIELDS) return ALL_SORT_FIELDS[paramSort as SortField];
    return "asc";
  });
  const [page, setPage] = useState(Number(searchParams.get("page")) || 1);
  const [showChart, setShowChart] = useState(false);
  const [listKey, setListKey] = useState(0);
  const prevIsFilteringRef = useRef(false);

  const activeRankField: "csRanking" | "nicheRanking" =
    rankSource === "niche" ? "nicheRanking" : "csRanking";
  const sortOptions = useMemo(() => getSortOptions(rankSource), [rankSource]);

  const { pendingFilters, clearPendingFilters } = useChatContext();
  const [previousFilters, setPreviousFilters] = useState<{
    search: string;
    stateFilter: string;
    regionFilter: string;
    sortBy: SortField;
    sortDir: "asc" | "desc";
    page: number;
    rankSource: RankSource;
  } | null>(null);

  const currentFiltersRef = useRef({
    search,
    stateFilter,
    regionFilter,
    sortBy,
    sortDir,
    page,
    rankSource,
  });
  useEffect(() => {
    currentFiltersRef.current = {
      search,
      stateFilter,
      regionFilter,
      sortBy,
      sortDir,
      page,
      rankSource,
    };
  }, [search, stateFilter, regionFilter, sortBy, sortDir, page, rankSource]);

  const handleRankSourceChange = useCallback(
    (source: RankSource) => {
      const oldField = rankSource === "niche" ? "nicheRanking" : "csRanking";
      const newField = source === "niche" ? "nicheRanking" : "csRanking";
      setRankSource(source);
      if (sortBy === oldField) setSortBy(newField);
      setPage(1);
    },
    [rankSource, sortBy]
  );

  useEffect(() => {
    if (!pendingFilters) return;
    setPreviousFilters({ ...currentFiltersRef.current });
    if (pendingFilters.rankSource) handleRankSourceChange(pendingFilters.rankSource);
    if (pendingFilters.sortBy) setSortBy(pendingFilters.sortBy as SortField);
    if (pendingFilters.sortDir) setSortDir(pendingFilters.sortDir);
    if (pendingFilters.state !== undefined) setStateFilter(pendingFilters.state);
    if (pendingFilters.region !== undefined) setRegionFilter(pendingFilters.region);
    if (pendingFilters.search !== undefined) setSearch(pendingFilters.search);
    setPage(1);
    clearPendingFilters();
  }, [pendingFilters, clearPendingFilters, handleRankSourceChange]);

  const undoChatFilters = useCallback(() => {
    if (!previousFilters) return;
    setSearch(previousFilters.search);
    setStateFilter(previousFilters.stateFilter);
    setRegionFilter(previousFilters.regionFilter);
    setSortBy(previousFilters.sortBy);
    setSortDir(previousFilters.sortDir);
    setPage(previousFilters.page);
    setRankSource(previousFilters.rankSource);
    setPreviousFilters(null);
  }, [previousFilters]);

  const schools = useMemo(
    () =>
      (rankSource === "niche" ? nicheSchools : csrankingsSchools).filter((school) => school.state),
    [rankSource, nicheSchools, csrankingsSchools]
  );

  const states = useMemo(() => {
    const stateSet = new Set(
      schools.map((school) => school.state).filter((s): s is string => s != null)
    );
    return Array.from(stateSet).sort();
  }, [schools]);

  const regions = useMemo(() => {
    const regionSet = new Set(
      schools.map((school) => school.region).filter((r): r is Exclude<typeof r, null> => r != null)
    );
    return Array.from(regionSet).sort();
  }, [schools]);

  const debouncedSearch = useDebounce(search, 300);

  // Sync state to URL search params (shareable URLs)
  // Uses window.history.replaceState to avoid React router re-renders
  useEffect(() => {
    const params = new URLSearchParams();
    if (debouncedSearch) params.set("q", debouncedSearch);
    if (stateFilter) params.set("state", stateFilter);
    if (regionFilter) params.set("region", regionFilter);
    params.set("rank", rankSource);
    if (sortBy !== activeRankField) params.set("sort", sortBy);
    if (sortDir !== "asc") params.set("dir", sortDir);
    if (page > 1) params.set("page", String(page));

    const paramString = params.toString();
    const newUrl = paramString ? `/?${paramString}` : "/";
    window.history.replaceState(null, "", newUrl);
  }, [
    debouncedSearch,
    stateFilter,
    regionFilter,
    rankSource,
    activeRankField,
    sortBy,
    sortDir,
    page,
  ]);

  // Run filter+sort once; derive pagination from the full sorted result
  const allFiltered = useMemo(
    () =>
      filterSchools(schools, {
        search: debouncedSearch || undefined,
        state: stateFilter || undefined,
        region: regionFilter || undefined,
        sortBy,
        sortDir,
        rankField: activeRankField,
      }),
    [schools, debouncedSearch, stateFilter, regionFilter, sortBy, sortDir, activeRankField]
  );

  const result = useMemo((): FilterResult => {
    const totalCount = allFiltered.length;
    const safePage = Math.max(1, page);
    const totalPages = Math.max(1, Math.ceil(totalCount / PER_PAGE));
    const currentPage = Math.min(safePage, totalPages);
    const schools2 = allFiltered.slice((currentPage - 1) * PER_PAGE, currentPage * PER_PAGE);
    return { schools: schools2, totalCount, totalPages, currentPage };
  }, [allFiltered, page]);

  const paginated = result.schools;
  const totalPages = result.totalPages;
  const defaultSortField: SortField = rankSource === "niche" ? "nicheRanking" : "csRanking";
  const hasActiveFilters = !!(
    search ||
    stateFilter ||
    regionFilter ||
    rankSource !== "niche" ||
    sortBy !== defaultSortField
  );

  // Derive filtering state: true while the debounce hasn't caught up with the typed search
  const isFiltering = debouncedSearch !== search;

  // Trigger list re-render animation when filters settle
  useEffect(() => {
    const wasFiltering = prevIsFilteringRef.current;
    if (wasFiltering && !isFiltering) {
      requestAnimationFrame(() => {
        setListKey((prev) => prev + 1);
      });
    }
    prevIsFilteringRef.current = isFiltering;
  }, [isFiltering]);

  // Reset to page 1 when filters change
  const updateFilter = useCallback(
    <T,>(setter: React.Dispatch<React.SetStateAction<T>>, value: T) => {
      setter(value);
      setPage(1);
    },
    []
  );

  const clearAllFilters = useCallback(() => {
    setSearch("");
    setStateFilter("");
    setRegionFilter("");
    setRankSource("niche");
    setSortBy("nicheRanking");
    setSortDir("asc");
    setPage(1);
  }, []);

  const toggleSort = useCallback(
    (key: SortField) => {
      if (sortBy === key) {
        setSortDir((d) => (d === "asc" ? "desc" : "asc"));
      } else {
        const option = sortOptions.find((o) => o.value === key);
        setSortBy(key);
        setSortDir(option?.defaultDir ?? "desc");
      }
      setPage(1);
    },
    [sortBy, sortOptions]
  );

  return (
    <div className="space-y-4">
      {/* Search + dropdowns */}
      <div className="flex flex-wrap gap-3">
        <div className="relative flex-1 min-w-[200px]">
          <input
            type="text"
            placeholder="Search schools..."
            value={search}
            onChange={(e) => updateFilter(setSearch, e.target.value.slice(0, 100))}
            maxLength={100}
            className="w-full px-4 py-2 bg-mantle border border-surface0 rounded-lg text-text placeholder:text-overlay0 focus:outline-none focus:ring-2 focus:ring-primary transition-all duration-150 ease-out pr-8"
            aria-label="Search schools"
          />
          {search && (
            <button
              onClick={() => updateFilter(setSearch, "" as string)}
              className="absolute right-2.5 top-1/2 -translate-y-1/2 text-overlay0 hover:text-text transition-colors duration-150 hover:scale-110 active:scale-95 transform"
              aria-label="Clear search"
            >
              <svg
                width="14"
                height="14"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth="2.5"
              >
                <line x1="18" y1="6" x2="6" y2="18" />
                <line x1="6" y1="6" x2="18" y2="18" />
              </svg>
            </button>
          )}
        </div>
        <Select
          id="state-filter"
          value={stateFilter}
          onChange={(v) => updateFilter(setStateFilter, v)}
          placeholder="All States"
          aria-label="Filter by state"
          options={[
            { value: "", label: "All States" },
            ...states.map((s) => ({ value: s, label: s })),
          ]}
        />
        <Select
          id="region-filter"
          value={regionFilter}
          onChange={(v) => updateFilter(setRegionFilter, v)}
          placeholder="All Regions"
          aria-label="Filter by region"
          options={[
            { value: "", label: "All Regions" },
            ...regions.map((r) => ({ value: r, label: r })),
          ]}
        />
      </div>

      {/* Ranking source toggle */}
      <div className="flex items-center gap-1 text-sm">
        <span className="text-subtext0 font-medium mr-1">Ranking:</span>
        <div className="relative group flex items-center">
          <span className="text-subtext0 cursor-help mr-1" aria-label="Ranking source info">
            ⓘ
          </span>
          <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 w-64 p-2 bg-crust text-text text-xs rounded shadow-lg border border-surface0 opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-200 z-10 pointer-events-none text-center">
            Niche ranks based on student reviews; CSRankings ranks based on faculty research
            publications
            <div className="absolute top-full left-1/2 -translate-x-1/2 border-4 border-transparent border-t-crust"></div>
          </div>
        </div>
        <div className="inline-flex rounded-lg border border-surface0 overflow-hidden">
          <button
            key="niche"
            onClick={() => handleRankSourceChange("niche")}
            title="Niche: student reviews covering academics, campus life, food, safety, and more"
            className={`px-3 py-1 text-xs font-medium transition-all duration-150 ease-out transform active:scale-95 ${
              rankSource === "niche"
                ? "bg-primary text-on-primary"
                : "bg-mantle text-subtext0 hover:bg-surface0"
            }`}
            aria-label="Use Niche rankings"
          >
            Niche
          </button>
          <button
            key="csrankings"
            onClick={() => handleRankSourceChange("csrankings")}
            title="CSRankings: based on faculty research publications — best for evaluating CS research strength"
            className={`px-3 py-1 text-xs font-medium transition-all duration-150 ease-out transform active:scale-95 ${
              rankSource === "csrankings"
                ? "bg-primary text-on-primary"
                : "bg-mantle text-subtext0 hover:bg-surface0"
            }`}
            aria-label="Use CSRankings rankings"
          >
            CSRankings
          </button>
        </div>
      </div>

      {/* Sort pills */}
      <div className="flex items-start gap-2 flex-wrap text-sm">
        <span className="text-subtext0 font-medium py-0.5 shrink-0">Sort:</span>
        <div className="flex flex-wrap gap-1.5">
          {sortOptions.map(({ value: key, label }) => (
            <button
              key={key}
              onClick={() => toggleSort(key)}
              className={`px-2.5 py-0.5 rounded-full transition-all duration-150 ease-out text-xs transform hover:scale-105 active:scale-95 ${
                sortBy === key
                  ? "bg-primary text-on-primary font-bold"
                  : "bg-surface0 text-text hover:bg-surface1"
              }`}
              style={{ transitionTimingFunction: "cubic-bezier(0.4, 0, 0.2, 1)" }}
              aria-label={`Sort by ${label}${sortBy === key ? `, currently ${sortDir === "asc" ? "ascending" : "descending"}, click to reverse` : ""}`}
            >
              {label}
              {sortBy === key && (sortDir === "asc" ? " ↑" : " ↓")}
            </button>
          ))}
        </div>
      </div>

      {/* Results count */}
      <p className="text-sm text-subtext0" aria-live="polite" aria-atomic="true">
        {isFiltering ? "Filtering..." : `${result.totalCount} schools`}
      </p>

      {/* AI filter undo banner */}
      {previousFilters && (
        <div
          className="flex items-center gap-3 px-4 py-2 bg-primary/10 border border-primary/20 rounded-lg text-sm transition-all duration-300 ease-out"
          style={{ animation: "fadeInUp 0.3s ease-out" }}
        >
          <span className="text-text">AI updated your filters.</span>
          <button
            onClick={undoChatFilters}
            className="text-primary font-medium hover:underline transition-all duration-150 transform hover:scale-105 active:scale-95"
          >
            Undo
          </button>
        </div>
      )}

      {/* Chart toggle */}
      <div className="flex items-center justify-between">
        <button
          onClick={() => setShowChart((v) => !v)}
          className="text-sm px-3 py-1.5 rounded-lg bg-surface0 text-text hover:bg-surface1 transition-all duration-150 ease-out transform hover:scale-105 active:scale-95"
          style={{ transitionTimingFunction: "cubic-bezier(0.4, 0, 0.2, 1)" }}
        >
          {showChart ? "Hide Chart" : "Show ROI Chart"}
        </button>
      </div>
      {showChart && (
        <div
          className="bg-mantle rounded-lg border border-surface0 p-4 transition-all duration-300 ease-out"
          style={{ animation: "fadeInUp 0.3s ease-out" }}
        >
          <h2 className="text-sm font-bold text-subtext0 mb-1">
            In-State Tuition vs Median Earnings (6yr) — up to 20 matching schools
          </h2>
          <p className="text-xs text-overlay0 mb-4">Top-left = best value (low cost, high earnings)</p>
          <ROIChart schools={allFiltered} />
        </div>
      )}

      {/* School list or empty state */}
      {paginated.length === 0 ? (
        <div className="text-center py-12">
          <p className="text-xl font-bold text-text mb-2">No schools found</p>
          <p className="text-subtext0 mb-4">
            {hasActiveFilters
              ? "Try adjusting your filters or search terms."
              : "No schools match the current criteria."}
          </p>
          {hasActiveFilters && (
            <button
              onClick={clearAllFilters}
              className="px-4 py-2 bg-primary text-on-primary rounded-lg hover:opacity-90 transition-all duration-150 ease-out transform hover:scale-105 active:scale-95 text-sm font-medium"
              style={{ transitionTimingFunction: "cubic-bezier(0.4, 0, 0.2, 1)" }}
            >
              Clear all filters
            </button>
          )}
        </div>
      ) : (
        /* School cards */
        <div key={listKey} className="space-y-3">
          {paginated.map((school, index) => {
            const payback = calculatePaybackYears(school);
            return (
              <Link
                key={school.slug}
                href={`/school/${school.slug}`}
                className="
                  block p-5 bg-mantle rounded-lg border border-surface0
                  hover:border-primary hover:shadow-[0_0_0_1px_var(--ctp-primary)]
                  hover:-translate-y-0.5 active:translate-y-0
                  transition-all duration-200 ease-out
                  transform hover:scale-[1.005] active:scale-[0.995]
                "
                style={{
                  transitionTimingFunction: "cubic-bezier(0.4, 0, 0.2, 1)",
                  animationDelay: `${index * 30}ms`,
                  animation: `fadeInUp 0.3s ease-out ${index * 30}ms both`,
                }}
              >
                <div className="flex items-start gap-4">
                  <SchoolLogo website={school.website} name={school.name} size={48} />
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 mb-1">
                      <span className="text-primary font-mono text-sm font-bold">
                        {school[activeRankField] ? `#${school[activeRankField]}` : "—"}
                      </span>
                      <span className="font-semibold text-lg truncate">{school.name}</span>
                    </div>
                    <p className="text-subtext0 text-sm">
                      {school.city}, {school.state} · {school.region}
                    </p>
                    {/* Mobile: heart + compare */}
                    <div className="sm:hidden flex items-center gap-2 mt-1">
                      <HeartButton slug={school.slug} size="sm" />
                      <CompareButton slug={school.slug} name={school.name} />
                    </div>
                    {/* Mobile: compact stats inline */}
                    <div className="sm:hidden flex gap-3 text-xs text-subtext0 mt-1">
                      <span className="text-peach">{formatCurrency(school.tuitionInState)}</span>
                      <span className="text-green">{formatCurrency(school.medianEarnings6yr)}</span>
                      {payback && <span className="text-blue">{payback.toFixed(1)}yr payback</span>}
                    </div>
                    <div className="flex flex-wrap gap-3 mt-3">
                      <GradeBadge grade={school.nicheGrades.overall} label="Overall" />
                      <GradeBadge grade={school.nicheGrades.academics} label="Academics" />
                      <GradeBadge grade={school.nicheGrades.campusFood} label="Food" />
                      <GradeBadge grade={school.nicheGrades.partyScene} label="Party" />
                      <GradeBadge grade={school.nicheGrades.studentLife} label="Social" />
                      <GradeBadge grade={school.nicheGrades.safety} label="Safety" />
                    </div>
                  </div>
                  {/* Desktop: stacked right-aligned stats */}
                  <div className="hidden sm:block text-right text-sm space-y-1 shrink-0">
                    <div className="flex justify-end gap-2 mb-1">
                      <CompareButton slug={school.slug} name={school.name} />
                      <HeartButton slug={school.slug} size="sm" />
                    </div>
                    <div>
                      <span className="text-subtext0">In-state: </span>
                      <span className="font-medium text-peach">{formatCurrency(school.tuitionInState)}</span>
                    </div>
                    <div>
                      <span className="text-subtext0">Out-of-state: </span>
                      <span className="font-medium text-peach">{formatCurrency(school.tuitionOutOfState)}</span>
                    </div>
                    <div>
                      <span className="text-subtext0">Earnings: </span>
                      <span className="font-medium text-green">
                        {formatCurrency(school.medianEarnings6yr)}
                      </span>
                    </div>
                    <div>
                      <span className="text-subtext0">Accept: </span>
                      <span className="font-medium">{formatPercent(school.acceptanceRate)}</span>
                    </div>
                    {payback && (
                      <div>
                        <span className="text-subtext0">Payback: </span>
                        <span className="font-medium text-blue">{payback.toFixed(1)}yr</span>
                      </div>
                    )}
                  </div>
                </div>
              </Link>
            );
          })}
        </div>
      )}

      {/* Pagination */}
      {result.totalCount > 0 && (
        <Pagination
          currentPage={page}
          totalPages={totalPages}
          onPageChange={(p) => {
            setPage(p);
            window.scrollTo({ top: 0, behavior: "smooth" });
          }}
        />
      )}
    </div>
  );
}

"use client";

import { useState, useMemo, useEffect, useCallback, useRef } from "react";
import { useSearchParams } from "next/navigation";
import Link from "next/link";
import dynamic from "next/dynamic";
import type { School } from "@/lib/data/schema";
import { useDebounce } from "@/hooks/useDebounce";
import GradeBadge from "./GradeBadge";
import Pagination from "./Pagination";
import SchoolLogo from "./SchoolLogo";
import { useChatContext } from "./ChatProvider";
import HeartButton from "./HeartButton";
import CompareButton from "./CompareButton";
import Select from "./Select";

const ROIChart = dynamic(() => import("./ROIChart"), { ssr: false });

// Import filtering logic from client-safe filters.ts (NOT loadSchools.ts which uses Node.js fs)
import { filterSchools, calculatePaybackYears, type SortField, type FilterResult } from "@/lib/data/filters";
import { formatCurrency, formatPercent } from "@/utils/format";

interface SchoolListProps {
  csrankingsSchools: School[];
  nicheSchools: School[];
}

interface SortOption {
  value: SortField;
  label: string;
  defaultDir: "asc" | "desc";
}

type RankSource = "csrankings" | "niche";

function getSortOptions(rankSource: RankSource): SortOption[] {
  const rankField: SortField = rankSource === "niche" ? "nicheRanking" : "csRanking";
  return [
    { value: rankField, label: "Ranking", defaultDir: "asc" },
    { value: "roi", label: "ROI", defaultDir: "asc" },
    { value: "earnings", label: "Earnings", defaultDir: "desc" },
    { value: "tuitionInState", label: "Tuition", defaultDir: "asc" },
    { value: "acceptanceRate", label: "Acceptance", defaultDir: "asc" },
    { value: "academics", label: "Academics", defaultDir: "desc" },
    { value: "value", label: "Value", defaultDir: "desc" },
    { value: "campusFood", label: "Food", defaultDir: "desc" },
    { value: "dorms", label: "Dorms", defaultDir: "desc" },
    { value: "safety", label: "Safety", defaultDir: "desc" },
    { value: "diversity", label: "Diversity", defaultDir: "desc" },
    { value: "professors", label: "Professors", defaultDir: "desc" },
    { value: "studentLife", label: "Social", defaultDir: "desc" },
    { value: "partyScene", label: "Party", defaultDir: "desc" },
    { value: "athletics", label: "Athletics", defaultDir: "desc" },
    { value: "location", label: "Location", defaultDir: "desc" },
  ];
}

// All valid sort fields and their default sort direction — used to validate URL params
// including niche grade fields set by the AI (not shown in the UI sort pills)
const ALL_SORT_FIELDS: Record<SortField, "asc" | "desc"> = {
  csRanking: "asc",
  nicheRanking: "asc",
  roi: "asc",
  earnings: "desc",
  tuitionInState: "asc",
  tuitionOutOfState: "asc",
  acceptanceRate: "asc",
  graduationRate: "desc",
  medianDebt: "asc",
  enrollment: "desc",
  campusFood: "desc",
  dorms: "desc",
  safety: "desc",
  partyScene: "desc",
  diversity: "desc",
  studentLife: "desc",
  professors: "desc",
  athletics: "desc",
  value: "desc",
  location: "desc",
  academics: "desc",
};

const PER_PAGE = 10;

export default function SchoolList({ csrankingsSchools, nicheSchools }: SchoolListProps) {
  const searchParams = useSearchParams();

  // Initialize state from URL search params (enables shareable/bookmarkable URLs)
  const [rankSource, setRankSource] = useState<RankSource>(() => {
    const param = searchParams.get("rank");
    return param === "csrankings" ? "csrankings" : "niche";
  });
  const [search, setSearch] = useState(searchParams.get("q") ?? "");
  const [stateFilter, setStateFilter] = useState(searchParams.get("state") ?? "");
  const [regionFilter, setRegionFilter] = useState(searchParams.get("region") ?? "");
  const [sortBy, setSortBy] = useState<SortField>(() => {
    const param = searchParams.get("sort");
    const src = searchParams.get("rank") === "csrankings" ? "csrankings" : "niche";
    const defaultField: SortField = src === "niche" ? "nicheRanking" : "csRanking";
    if (!param || param === "ranking") return defaultField;
    return param in ALL_SORT_FIELDS ? (param as SortField) : defaultField;
  });
  const [sortDir, setSortDir] = useState<"asc" | "desc">(() => {
    const dir = searchParams.get("dir");
    if (dir === "asc" || dir === "desc") return dir;
    const paramSort = searchParams.get("sort");
    if (paramSort && paramSort in ALL_SORT_FIELDS) return ALL_SORT_FIELDS[paramSort as SortField];
    return "asc";
  });
  const [page, setPage] = useState(Number(searchParams.get("page")) || 1);
  const [showChart, setShowChart] = useState(false);
  const [listKey, setListKey] = useState(0);
  const prevIsFilteringRef = useRef(false);

  const activeRankField: "csRanking" | "nicheRanking" =
    rankSource === "niche" ? "nicheRanking" : "csRanking";
  const sortOptions = useMemo(() => getSortOptions(rankSource), [rankSource]);

  const { pendingFilters, clearPendingFilters } = useChatContext();
  const [previousFilters, setPreviousFilters] = useState<{
    search: string;
    stateFilter: string;
    regionFilter: string;
    sortBy: SortField;
    sortDir: "asc" | "desc";
    page: number;
    rankSource: RankSource;
  } | null>(null);

  const currentFiltersRef = useRef({
    search,
    stateFilter,
    regionFilter,
    sortBy,
    sortDir,
    page,
    rankSource,
  });
  useEffect(() => {
    currentFiltersRef.current = {
      search,
      stateFilter,
      regionFilter,
      sortBy,
      sortDir,
      page,
      rankSource,
    };
  }, [search, stateFilter, regionFilter, sortBy, sortDir, page, rankSource]);

  const handleRankSourceChange = useCallback(
    (source: RankSource) => {
      const oldField = rankSource === "niche" ? "nicheRanking" : "csRanking";
      const newField = source === "niche" ? "nicheRanking" : "csRanking";
      setRankSource(source);
      if (sortBy === oldField) setSortBy(newField);
      setPage(1);
    },
    [rankSource, sortBy]
  );

  useEffect(() => {
    if (!pendingFilters) return;
    setPreviousFilters({ ...currentFiltersRef.current });
    if (pendingFilters.rankSource) handleRankSourceChange(pendingFilters.rankSource);
    if (pendingFilters.sortBy) setSortBy(pendingFilters.sortBy as SortField);
    if (pendingFilters.sortDir) setSortDir(pendingFilters.sortDir);
    if (pendingFilters.state !== undefined) setStateFilter(pendingFilters.state);
    if (pendingFilters.region !== undefined) setRegionFilter(pendingFilters.region);
    if (pendingFilters.search !== undefined) setSearch(pendingFilters.search);
    setPage(1);
    clearPendingFilters();
  }, [pendingFilters, clearPendingFilters, handleRankSourceChange]);

  const undoChatFilters = useCallback(() => {
    if (!previousFilters) return;
    setSearch(previousFilters.search);
    setStateFilter(previousFilters.stateFilter);
    setRegionFilter(previousFilters.regionFilter);
    setSortBy(previousFilters.sortBy);
    setSortDir(previousFilters.sortDir);
    setPage(previousFilters.page);
    setRankSource(previousFilters.rankSource);
    setPreviousFilters(null);
  }, [previousFilters]);

  const schools = useMemo(
    () =>
      (rankSource === "niche" ? nicheSchools : csrankingsSchools).filter((school) => school.state),
    [rankSource, nicheSchools, csrankingsSchools]
  );

  const states = useMemo(() => {
    const stateSet = new Set(
      schools.map((school) => school.state).filter((s): s is string => s != null)
    );
    return Array.from(stateSet).sort();
  }, [schools]);

  const regions = useMemo(() => {
    const regionSet = new Set(
      schools.map((school) => school.region).filter((r): r is Exclude<typeof r, null> => r != null)
    );
    return Array.from(regionSet).sort();
  }, [schools]);

  const debouncedSearch = useDebounce(search, 300);

  // Sync state to URL search params (shareable URLs)
  // Uses window.history.replaceState to avoid React router re-renders
  useEffect(() => {
    const params = new URLSearchParams();
    if (debouncedSearch) params.set("q", debouncedSearch);
    if (stateFilter) params.set("state", stateFilter);
    if (regionFilter) params.set("region", regionFilter);
    params.set("rank", rankSource);
    if (sortBy !== activeRankField) params.set("sort", sortBy);
    if (sortDir !== "asc") params.set("dir", sortDir);
    if (page > 1) params.set("page", String(page));

    const paramString = params.toString();
    const newUrl = paramString ? `/?${paramString}` : "/";
    window.history.replaceState(null, "", newUrl);
  }, [
    debouncedSearch,
    stateFilter,
    regionFilter,
    rankSource,
    activeRankField,
    sortBy,
    sortDir,
    page,
  ]);

  // Run filter+sort once; derive pagination from the full sorted result
  const allFiltered = useMemo(
    () =>
      filterSchools(schools, {
        search: debouncedSearch || undefined,
        state: stateFilter || undefined,
        region: regionFilter || undefined,
        sortBy,
        sortDir,
        rankField: activeRankField,
      }),
    [schools, debouncedSearch, stateFilter, regionFilter, sortBy, sortDir, activeRankField]
  );

  const result = useMemo((): FilterResult => {
    const totalCount = allFiltered.length;
    const safePage = Math.max(1, page);
    const totalPages = Math.max(1, Math.ceil(totalCount / PER_PAGE));
    const currentPage = Math.min(safePage, totalPages);
    const schools2 = allFiltered.slice((currentPage - 1) * PER_PAGE, currentPage * PER_PAGE);
    return { schools: schools2, totalCount, totalPages, currentPage };
  }, [allFiltered, page]);

  const paginated = result.schools;
  const totalPages = result.totalPages;
  const defaultSortField: SortField = rankSource === "niche" ? "nicheRanking" : "csRanking";
  const hasActiveFilters = !!(
    search ||
    stateFilter ||
    regionFilter ||
    rankSource !== "niche" ||
    sortBy !== defaultSortField
  );

  // Derive filtering state: true while the debounce hasn't caught up with the typed search
  const isFiltering = debouncedSearch !== search;

  // Trigger list re-render animation when filters settle
  useEffect(() => {
    const wasFiltering = prevIsFilteringRef.current;
    if (wasFiltering && !isFiltering) {
      requestAnimationFrame(() => {
        setListKey((prev) => prev + 1);
      });
    }
    prevIsFilteringRef.current = isFiltering;
  }, [isFiltering]);

  // Reset to page 1 when filters change
  const updateFilter = useCallback(
    <T,>(setter: React.Dispatch<React.SetStateAction<T>>, value: T) => {
      setter(value);
      setPage(1);
    },
    []
  );

  const clearAllFilters = useCallback(() => {
    setSearch("");
    setStateFilter("");
    setRegionFilter("");
    setRankSource("niche");
    setSortBy("nicheRanking");
    setSortDir("asc");
    setPage(1);
  }, []);

  const toggleSort = useCallback(
    (key: SortField) => {
      if (sortBy === key) {
        setSortDir((d) => (d === "asc" ? "desc" : "asc"));
      } else {
        const option = sortOptions.find((o) => o.value === key);
        setSortBy(key);
        setSortDir(option?.defaultDir ?? "desc");
      }
      setPage(1);
    },
    [sortBy, sortOptions]
  );

  return (
    <div className="space-y-4">
      {/* Search + dropdowns */}
      <div className="flex flex-wrap gap-3">
        <div className="relative flex-1 min-w-[200px]">
          <input
            type="text"
            placeholder="Search schools..."
            value={search}
            onChange={(e) => updateFilter(setSearch, e.target.value.slice(0, 100))}
            maxLength={100}
            className="w-full px-4 py-2 bg-mantle border border-surface0 rounded-lg text-text placeholder:text-overlay0 focus:outline-none focus:ring-2 focus:ring-primary transition-all duration-150 ease-out pr-8"
            aria-label="Search schools"
          />
          {search && (
            <button
              onClick={() => updateFilter(setSearch, "" as string)}
              className="absolute right-2.5 top-1/2 -translate-y-1/2 text-overlay0 hover:text-text transition-colors duration-150 hover:scale-110 active:scale-95 transform"
              aria-label="Clear search"
            >
              <svg
                width="14"
                height="14"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth="2.5"
              >
                <line x1="18" y1="6" x2="6" y2="18" />
                <line x1="6" y1="6" x2="18" y2="18" />
              </svg>
            </button>
          )}
        </div>
        <Select
          id="state-filter"
          value={stateFilter}
          onChange={(v) => updateFilter(setStateFilter, v)}
          placeholder="All States"
          aria-label="Filter by state"
          options={[
            { value: "", label: "All States" },
            ...states.map((s) => ({ value: s, label: s })),
          ]}
        />
        <Select
          id="region-filter"
          value={regionFilter}
          onChange={(v) => updateFilter(setRegionFilter, v)}
          placeholder="All Regions"
          aria-label="Filter by region"
          options={[
            { value: "", label: "All Regions" },
            ...regions.map((r) => ({ value: r, label: r })),
          ]}
        />
      </div>

      {/* Ranking source toggle */}
      <div className="flex items-center gap-1 text-sm">
        <span className="text-subtext0 font-medium mr-1">Ranking:</span>
        <div className="relative group flex items-center">
          <span className="text-subtext0 cursor-help mr-1" aria-label="Ranking source info">
            ⓘ
          </span>
          <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 w-64 p-2 bg-crust text-text text-xs rounded shadow-lg border border-surface0 opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-200 z-10 pointer-events-none text-center">
            Niche ranks based on student reviews; CSRankings ranks based on faculty research
            publications
            <div className="absolute top-full left-1/2 -translate-x-1/2 border-4 border-transparent border-t-crust"></div>
          </div>
        </div>
        <div className="inline-flex rounded-lg border border-surface0 overflow-hidden">
          <button
            key="niche"
            onClick={() => handleRankSourceChange("niche")}
            title="Niche: student reviews covering academics, campus life, food, safety, and more"
            className={`px-3 py-1 text-xs font-medium transition-all duration-150 ease-out transform active:scale-95 ${
              rankSource === "niche"
                ? "bg-primary text-on-primary"
                : "bg-mantle text-subtext0 hover:bg-surface0"
            }`}
            aria-label="Use Niche rankings"
          >
            Niche
          </button>
          <button
            key="csrankings"
            onClick={() => handleRankSourceChange("csrankings")}
            title="CSRankings: based on faculty research publications — best for evaluating CS research strength"
            className={`px-3 py-1 text-xs font-medium transition-all duration-150 ease-out transform active:scale-95 ${
              rankSource === "csrankings"
                ? "bg-primary text-on-primary"
                : "bg-mantle text-subtext0 hover:bg-surface0"
            }`}
            aria-label="Use CSRankings rankings"
          >
            CSRankings
          </button>
        </div>
      </div>

      {/* Sort pills */}
      <div className="flex items-start gap-2 flex-wrap text-sm">
        <span className="text-subtext0 font-medium py-0.5 shrink-0">Sort:</span>
        <div className="flex flex-wrap gap-1.5">
          {sortOptions.map(({ value: key, label }) => (
            <button
              key={key}
              onClick={() => toggleSort(key)}
              className={`px-2.5 py-0.5 rounded-full transition-all duration-150 ease-out text-xs transform hover:scale-105 active:scale-95 ${
                sortBy === key
                  ? "bg-primary text-on-primary font-bold"
                  : "bg-surface0 text-text hover:bg-surface1"
              }`}
              style={{ transitionTimingFunction: "cubic-bezier(0.4, 0, 0.2, 1)" }}
              aria-label={`Sort by ${label}${sortBy === key ? `, currently ${sortDir === "asc" ? "ascending" : "descending"}, click to reverse` : ""}`}
            >
              {label}
              {sortBy === key && (sortDir === "asc" ? " ↑" : " ↓")}
            </button>
          ))}
        </div>
      </div>

      {/* Results count */}
      <p className="text-sm text-subtext0" aria-live="polite" aria-atomic="true">
        {isFiltering ? "Filtering..." : `${result.totalCount} schools`}
      </p>

      {/* AI filter undo banner */}
      {previousFilters && (
        <div
          className="flex items-center gap-3 px-4 py-2 bg-primary/10 border border-primary/20 rounded-lg text-sm transition-all duration-300 ease-out"
          style={{ animation: "fadeInUp 0.3s ease-out" }}
        >
          <span className="text-text">AI updated your filters.</span>
          <button
            onClick={undoChatFilters}
            className="text-primary font-medium hover:underline transition-all duration-150 transform hover:scale-105 active:scale-95"
          >
            Undo
          </button>
        </div>
      )}

      {/* Chart toggle */}
      <div className="flex items-center justify-between">
        <button
          onClick={() => setShowChart((v) => !v)}
          className="text-sm px-3 py-1.5 rounded-lg bg-surface0 text-text hover:bg-surface1 transition-all duration-150 ease-out transform hover:scale-105 active:scale-95"
          style={{ transitionTimingFunction: "cubic-bezier(0.4, 0, 0.2, 1)" }}
        >
          {showChart ? "Hide Chart" : "Show ROI Chart"}
        </button>
      </div>
      {showChart && (
        <div
          className="bg-mantle rounded-lg border border-surface0 p-4 transition-all duration-300 ease-out"
          style={{ animation: "fadeInUp 0.3s ease-out" }}
        >
          <h2 className="text-sm font-bold text-subtext0 mb-4">
            Tuition vs Median Earnings — top 15 matching schools
          </h2>
          <ROIChart schools={allFiltered} />
        </div>
      )}

      {/* School list or empty state */}
      {paginated.length === 0 ? (
        <div className="text-center py-12">
          <p className="text-xl font-bold text-text mb-2">No schools found</p>
          <p className="text-subtext0 mb-4">
            {hasActiveFilters
              ? "Try adjusting your filters or search terms."
              : "No schools match the current criteria."}
          </p>
          {hasActiveFilters && (
            <button
              onClick={clearAllFilters}
              className="px-4 py-2 bg-primary text-on-primary rounded-lg hover:opacity-90 transition-all duration-150 ease-out transform hover:scale-105 active:scale-95 text-sm font-medium"
              style={{ transitionTimingFunction: "cubic-bezier(0.4, 0, 0.2, 1)" }}
            >
              Clear all filters
            </button>
          )}
        </div>
      ) : (
        /* School cards */
        <div key={listKey} className="space-y-3">
          {paginated.map((school, index) => {
            const payback = calculatePaybackYears(school);
            return (
              <Link
                key={school.slug}
                href={`/school/${school.slug}`}
                className="
                  block p-5 bg-mantle rounded-lg border border-surface0
                  hover:border-primary hover:shadow-[0_0_0_1px_var(--ctp-primary)]
                  hover:-translate-y-0.5 active:translate-y-0
                  transition-all duration-200 ease-out
                  transform hover:scale-[1.005] active:scale-[0.995]
                "
                style={{
                  transitionTimingFunction: "cubic-bezier(0.4, 0, 0.2, 1)",
                  animationDelay: `${index * 30}ms`,
                  animation: `fadeInUp 0.3s ease-out ${index * 30}ms both`,
                }}
              >
                <div className="flex items-start gap-4">
                  <SchoolLogo website={school.website} name={school.name} size={48} />
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 mb-1">
                      <span className="text-primary font-mono text-sm font-bold">
                        {school[activeRankField] ? `#${school[activeRankField]}` : "—"}
                      </span>
                      <span className="font-semibold text-lg truncate">{school.name}</span>
                    </div>
                    <p className="text-subtext0 text-sm">
                      {school.city}, {school.state} · {school.region}
                    </p>
                    {/* Mobile: heart + compare */}
                    <div className="sm:hidden flex items-center gap-2 mt-1">
                      <HeartButton slug={school.slug} size="sm" />
                      <CompareButton slug={school.slug} name={school.name} />
                    </div>
                    {/* Mobile: compact stats inline */}
                    <div className="sm:hidden flex gap-3 text-xs text-subtext0 mt-1">
                      <span className="text-peach">{formatCurrency(school.tuitionInState)}</span>
                      <span className="text-green">{formatCurrency(school.medianEarnings6yr)}</span>
                      {payback && <span className="text-blue">{payback.toFixed(1)}yr payback</span>}
                    </div>
                    <div className="flex flex-wrap gap-3 mt-3">
                      <GradeBadge grade={school.nicheGrades.overall} label="Overall" />
                      <GradeBadge grade={school.nicheGrades.academics} label="Academics" />
                      <GradeBadge grade={school.nicheGrades.campusFood} label="Food" />
                      <GradeBadge grade={school.nicheGrades.partyScene} label="Party" />
                      <GradeBadge grade={school.nicheGrades.studentLife} label="Social" />
                      <GradeBadge grade={school.nicheGrades.safety} label="Safety" />
                    </div>
                  </div>
                  {/* Desktop: stacked right-aligned stats */}
                  <div className="hidden sm:block text-right text-sm space-y-1 shrink-0">
                    <div className="flex justify-end gap-2 mb-1">
                      <CompareButton slug={school.slug} name={school.name} />
                      <HeartButton slug={school.slug} size="sm" />
                    </div>
                    <div>
                      <span className="text-subtext0">In-state: </span>
                      <span className="font-medium text-peach">{formatCurrency(school.tuitionInState)}</span>
                    </div>
                    <div>
                      <span className="text-subtext0">Out-of-state: </span>
                      <span className="font-medium text-peach">{formatCurrency(school.tuitionOutOfState)}</span>
                    </div>
                    <div>
                      <span className="text-subtext0">Earnings: </span>
                      <span className="font-medium text-green">
                        {formatCurrency(school.medianEarnings6yr)}
                      </span>
                    </div>
                    <div>
                      <span className="text-subtext0">Accept: </span>
                      <span className="font-medium">{formatPercent(school.acceptanceRate)}</span>
                    </div>
                    {payback && (
                      <div>
                        <span className="text-subtext0">Payback: </span>
                        <span className="font-medium text-blue">{payback.toFixed(1)}yr</span>
                      </div>
                    )}
                  </div>
                </div>
              </Link>
            );
          })}
        </div>
      )}

      {/* Pagination */}
      {result.totalCount > 0 && (
        <Pagination
          currentPage={page}
          totalPages={totalPages}
          onPageChange={(p) => {
            setPage(p);
            window.scrollTo({ top: 0, behavior: "smooth" });
          }}
        />
      )}
    </div>
  );
}

"use client";

import { useState, useMemo, useEffect, useCallback, useRef } from "react";
import { useSearchParams } from "next/navigation";
import Link from "next/link";
import dynamic from "next/dynamic";
import type { School } from "@/lib/data/schema";
import { useDebounce } from "@/hooks/useDebounce";
import GradeBadge from "./GradeBadge";
import Pagination from "./Pagination";
import SchoolLogo from "./SchoolLogo";
import { useChatContext } from "./ChatProvider";
import HeartButton from "./HeartButton";
import CompareButton from "./CompareButton";
import Select from "./Select";

const ROIChart = dynamic(() => import("./ROIChart"), { ssr: false });

// Import filtering logic from client-safe filters.ts (NOT loadSchools.ts which uses Node.js fs)
import { filterSchools, calculatePaybackYears, type SortField, type FilterResult } from "@/lib/data/filters";
import { formatCurrency, formatPercent } from "@/utils/format";

interface SchoolListProps {
  csrankingsSchools: School[];
  nicheSchools: School[];
}

interface SortOption {
  value: SortField;
  label: string;
  defaultDir: "asc" | "desc";
}

type RankSource = "csrankings" | "niche";

function getSortOptions(rankSource: RankSource): SortOption[] {
  const rankField: SortField = rankSource === "niche" ? "nicheRanking" : "csRanking";
  return [
    { value: rankField, label: "Ranking", defaultDir: "asc" },
    { value: "roi", label: "ROI", defaultDir: "asc" },
    { value: "earnings", label: "Earnings", defaultDir: "desc" },
    { value: "tuitionInState", label: "Tuition", defaultDir: "asc" },
    { value: "acceptanceRate", label: "Acceptance", defaultDir: "asc" },
    { value: "academics", label: "Academics", defaultDir: "desc" },
    { value: "value", label: "Value", defaultDir: "desc" },
    { value: "campusFood", label: "Food", defaultDir: "desc" },
    { value: "dorms", label: "Dorms", defaultDir: "desc" },
    { value: "safety", label: "Safety", defaultDir: "desc" },
    { value: "diversity", label: "Diversity", defaultDir: "desc" },
    { value: "professors", label: "Professors", defaultDir: "desc" },
    { value: "studentLife", label: "Social", defaultDir: "desc" },
    { value: "partyScene", label: "Party", defaultDir: "desc" },
    { value: "athletics", label: "Athletics", defaultDir: "desc" },
    { value: "location", label: "Location", defaultDir: "desc" },
  ];
}

// All valid sort fields and their default sort direction — used to validate URL params
// including niche grade fields set by the AI (not shown in the UI sort pills)
const ALL_SORT_FIELDS: Record<SortField, "asc" | "desc"> = {
  csRanking: "asc",
  nicheRanking: "asc",
  roi: "asc",
  earnings: "desc",
  tuitionInState: "asc",
  tuitionOutOfState: "asc",
  acceptanceRate: "asc",
  graduationRate: "desc",
  medianDebt: "asc",
  enrollment: "desc",
  campusFood: "desc",
  dorms: "desc",
  safety: "desc",
  partyScene: "desc",
  diversity: "desc",
  studentLife: "desc",
  professors: "desc",
  athletics: "desc",
  value: "desc",
  location: "desc",
  academics: "desc",
};

const PER_PAGE = 10;

export default function SchoolList({ csrankingsSchools, nicheSchools }: SchoolListProps) {
  const searchParams = useSearchParams();

  // Initialize state from URL search params (enables shareable/bookmarkable URLs)
  const [rankSource, setRankSource] = useState<RankSource>(() => {
    const param = searchParams.get("rank");
    return param === "csrankings" ? "csrankings" : "niche";
  });
  const [search, setSearch] = useState(searchParams.get("q") ?? "");
  const [stateFilter, setStateFilter] = useState(searchParams.get("state") ?? "");
  const [regionFilter, setRegionFilter] = useState(searchParams.get("region") ?? "");
  const [sortBy, setSortBy] = useState<SortField>(() => {
    const param = searchParams.get("sort");
    const src = searchParams.get("rank") === "csrankings" ? "csrankings" : "niche";
    const defaultField: SortField = src === "niche" ? "nicheRanking" : "csRanking";
    if (!param || param === "ranking") return defaultField;
    return param in ALL_SORT_FIELDS ? (param as SortField) : defaultField;
  });
  const [sortDir, setSortDir] = useState<"asc" | "desc">(() => {
    const dir = searchParams.get("dir");
    if (dir === "asc" || dir === "desc") return dir;
    const paramSort = searchParams.get("sort");
    if (paramSort && paramSort in ALL_SORT_FIELDS) return ALL_SORT_FIELDS[paramSort as SortField];
    return "asc";
  });
  const [page, setPage] = useState(Number(searchParams.get("page")) || 1);
  const [showChart, setShowChart] = useState(false);
  const [listKey, setListKey] = useState(0);
  const prevIsFilteringRef = useRef(false);

  const activeRankField: "csRanking" | "nicheRanking" =
    rankSource === "niche" ? "nicheRanking" : "csRanking";
  const sortOptions = useMemo(() => getSortOptions(rankSource), [rankSource]);

  const { pendingFilters, clearPendingFilters } = useChatContext();
  const [previousFilters, setPreviousFilters] = useState<{
    search: string;
    stateFilter: string;
    regionFilter: string;
    sortBy: SortField;
    sortDir: "asc" | "desc";
    page: number;
    rankSource: RankSource;
  } | null>(null);

  const currentFiltersRef = useRef({
    search,
    stateFilter,
    regionFilter,
    sortBy,
    sortDir,
    page,
    rankSource,
  });
  useEffect(() => {
    currentFiltersRef.current = {
      search,
      stateFilter,
      regionFilter,
      sortBy,
      sortDir,
      page,
      rankSource,
    };
  }, [search, stateFilter, regionFilter, sortBy, sortDir, page, rankSource]);

  const handleRankSourceChange = useCallback(
    (source: RankSource) => {
      const oldField = rankSource === "niche" ? "nicheRanking" : "csRanking";
      const newField = source === "niche" ? "nicheRanking" : "csRanking";
      setRankSource(source);
      if (sortBy === oldField) setSortBy(newField);
      setPage(1);
    },
    [rankSource, sortBy]
  );

  useEffect(() => {
    if (!pendingFilters) return;
    setPreviousFilters({ ...currentFiltersRef.current });
    if (pendingFilters.rankSource) handleRankSourceChange(pendingFilters.rankSource);
    if (pendingFilters.sortBy) setSortBy(pendingFilters.sortBy as SortField);
    if (pendingFilters.sortDir) setSortDir(pendingFilters.sortDir);
    if (pendingFilters.state !== undefined) setStateFilter(pendingFilters.state);
    if (pendingFilters.region !== undefined) setRegionFilter(pendingFilters.region);
    if (pendingFilters.search !== undefined) setSearch(pendingFilters.search);
    setPage(1);
    clearPendingFilters();
  }, [pendingFilters, clearPendingFilters, handleRankSourceChange]);

  const undoChatFilters = useCallback(() => {
    if (!previousFilters) return;
    setSearch(previousFilters.search);
    setStateFilter(previousFilters.stateFilter);
    setRegionFilter(previousFilters.regionFilter);
    setSortBy(previousFilters.sortBy);
    setSortDir(previousFilters.sortDir);
    setPage(previousFilters.page);
    setRankSource(previousFilters.rankSource);
    setPreviousFilters(null);
  }, [previousFilters]);

  const schools = useMemo(
    () =>
      (rankSource === "niche" ? nicheSchools : csrankingsSchools).filter((school) => school.state),
    [rankSource, nicheSchools, csrankingsSchools]
  );

  const states = useMemo(() => {
    const stateSet = new Set(
      schools.map((school) => school.state).filter((s): s is string => s != null)
    );
    return Array.from(stateSet).sort();
  }, [schools]);

  const regions = useMemo(() => {
    const regionSet = new Set(
      schools.map((school) => school.region).filter((r): r is Exclude<typeof r, null> => r != null)
    );
    return Array.from(regionSet).sort();
  }, [schools]);

  const debouncedSearch = useDebounce(search, 300);

  // Sync state to URL search params (shareable URLs)
  // Uses window.history.replaceState to avoid React router re-renders
  useEffect(() => {
    const params = new URLSearchParams();
    if (debouncedSearch) params.set("q", debouncedSearch);
    if (stateFilter) params.set("state", stateFilter);
    if (regionFilter) params.set("region", regionFilter);
    params.set("rank", rankSource);
    if (sortBy !== activeRankField) params.set("sort", sortBy);
    if (sortDir !== "asc") params.set("dir", sortDir);
    if (page > 1) params.set("page", String(page));

    const paramString = params.toString();
    const newUrl = paramString ? `/?${paramString}` : "/";
    window.history.replaceState(null, "", newUrl);
  }, [
    debouncedSearch,
    stateFilter,
    regionFilter,
    rankSource,
    activeRankField,
    sortBy,
    sortDir,
    page,
  ]);

  // Run filter+sort once; derive pagination from the full sorted result
  const allFiltered = useMemo(
    () =>
      filterSchools(schools, {
        search: debouncedSearch || undefined,
        state: stateFilter || undefined,
        region: regionFilter || undefined,
        sortBy,
        sortDir,
        rankField: activeRankField,
      }),
    [schools, debouncedSearch, stateFilter, regionFilter, sortBy, sortDir, activeRankField]
  );

  const result = useMemo((): FilterResult => {
    const totalCount = allFiltered.length;
    const safePage = Math.max(1, page);
    const totalPages = Math.max(1, Math.ceil(totalCount / PER_PAGE));
    const currentPage = Math.min(safePage, totalPages);
    const schools2 = allFiltered.slice((currentPage - 1) * PER_PAGE, currentPage * PER_PAGE);
    return { schools: schools2, totalCount, totalPages, currentPage };
  }, [allFiltered, page]);

  const paginated = result.schools;
  const totalPages = result.totalPages;
  const defaultSortField: SortField = rankSource === "niche" ? "nicheRanking" : "csRanking";
  const hasActiveFilters = !!(
    search ||
    stateFilter ||
    regionFilter ||
    rankSource !== "niche" ||
    sortBy !== defaultSortField
  );

  // Derive filtering state: true while the debounce hasn't caught up with the typed search
  const isFiltering = debouncedSearch !== search;

  // Trigger list re-render animation when filters settle
  useEffect(() => {
    const wasFiltering = prevIsFilteringRef.current;
    if (wasFiltering && !isFiltering) {
      requestAnimationFrame(() => {
        setListKey((prev) => prev + 1);
      });
    }
    prevIsFilteringRef.current = isFiltering;
  }, [isFiltering]);

  // Reset to page 1 when filters change
  const updateFilter = useCallback(
    <T,>(setter: React.Dispatch<React.SetStateAction<T>>, value: T) => {
      setter(value);
      setPage(1);
    },
    []
  );

  const clearAllFilters = useCallback(() => {
    setSearch("");
    setStateFilter("");
    setRegionFilter("");
    setRankSource("niche");
    setSortBy("nicheRanking");
    setSortDir("asc");
    setPage(1);
  }, []);

  const toggleSort = useCallback(
    (key: SortField) => {
      if (sortBy === key) {
        setSortDir((d) => (d === "asc" ? "desc" : "asc"));
      } else {
        const option = sortOptions.find((o) => o.value === key);
        setSortBy(key);
        setSortDir(option?.defaultDir ?? "desc");
      }
      setPage(1);
    },
    [sortBy, sortOptions]
  );

  return (
    <div className="space-y-4">
      {/* Search + dropdowns */}
      <div className="flex flex-wrap gap-3">
        <div className="relative flex-1 min-w-[200px]">
          <input
            type="text"
            placeholder="Search schools..."
            value={search}
            onChange={(e) => updateFilter(setSearch, e.target.value.slice(0, 100))}
            maxLength={100}
            className="w-full px-4 py-2 bg-mantle border border-surface0 rounded-lg text-text placeholder:text-overlay0 focus:outline-none focus:ring-2 focus:ring-primary transition-all duration-150 ease-out pr-8"
            aria-label="Search schools"
          />
          {search && (
            <button
              onClick={() => updateFilter(setSearch, "" as string)}
              className="absolute right-2.5 top-1/2 -translate-y-1/2 text-overlay0 hover:text-text transition-colors duration-150 hover:scale-110 active:scale-95 transform"
              aria-label="Clear search"
            >
              <svg
                width="14"
                height="14"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth="2.5"
              >
                <line x1="18" y1="6" x2="6" y2="18" />
                <line x1="6" y1="6" x2="18" y2="18" />
              </svg>
            </button>
          )}
        </div>
        <Select
          id="state-filter"
          value={stateFilter}
          onChange={(v) => updateFilter(setStateFilter, v)}
          placeholder="All States"
          aria-label="Filter by state"
          options={[
            { value: "", label: "All States" },
            ...states.map((s) => ({ value: s, label: s })),
          ]}
        />
        <Select
          id="region-filter"
          value={regionFilter}
          onChange={(v) => updateFilter(setRegionFilter, v)}
          placeholder="All Regions"
          aria-label="Filter by region"
          options={[
            { value: "", label: "All Regions" },
            ...regions.map((r) => ({ value: r, label: r })),
          ]}
        />
      </div>

      {/* Ranking source toggle */}
      <div className="flex items-center gap-1 text-sm">
        <span className="text-subtext0 font-medium mr-1">Ranking:</span>
        <div className="relative group flex items-center">
          <span className="text-subtext0 cursor-help mr-1" aria-label="Ranking source info">
            ⓘ
          </span>
          <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 w-64 p-2 bg-crust text-text text-xs rounded shadow-lg border border-surface0 opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-200 z-10 pointer-events-none text-center">
            Niche ranks based on student reviews; CSRankings ranks based on faculty research
            publications
            <div className="absolute top-full left-1/2 -translate-x-1/2 border-4 border-transparent border-t-crust"></div>
          </div>
        </div>
        <div className="inline-flex rounded-lg border border-surface0 overflow-hidden">
          <button
            key="niche"
            onClick={() => handleRankSourceChange("niche")}
            title="Niche: student reviews covering academics, campus life, food, safety, and more"
            className={`px-3 py-1 text-xs font-medium transition-all duration-150 ease-out transform active:scale-95 ${
              rankSource === "niche"
                ? "bg-primary text-on-primary"
                : "bg-mantle text-subtext0 hover:bg-surface0"
            }`}
            aria-label="Use Niche rankings"
          >
            Niche
          </button>
          <button
            key="csrankings"
            onClick={() => handleRankSourceChange("csrankings")}
            title="CSRankings: based on faculty research publications — best for evaluating CS research strength"
            className={`px-3 py-1 text-xs font-medium transition-all duration-150 ease-out transform active:scale-95 ${
              rankSource === "csrankings"
                ? "bg-primary text-on-primary"
                : "bg-mantle text-subtext0 hover:bg-surface0"
            }`}
            aria-label="Use CSRankings rankings"
          >
            CSRankings
          </button>
        </div>
      </div>

      {/* Sort pills */}
      <div className="flex items-start gap-2 flex-wrap text-sm">
        <span className="text-subtext0 font-medium py-0.5 shrink-0">Sort:</span>
        <div className="flex flex-wrap gap-1.5">
          {sortOptions.map(({ value: key, label }) => (
            <button
              key={key}
              onClick={() => toggleSort(key)}
              className={`px-2.5 py-0.5 rounded-full transition-all duration-150 ease-out text-xs transform hover:scale-105 active:scale-95 ${
                sortBy === key
                  ? "bg-primary text-on-primary font-bold"
                  : "bg-surface0 text-text hover:bg-surface1"
              }`}
              style={{ transitionTimingFunction: "cubic-bezier(0.4, 0, 0.2, 1)" }}
              aria-label={`Sort by ${label}${sortBy === key ? `, currently ${sortDir === "asc" ? "ascending" : "descending"}, click to reverse` : ""}`}
            >
              {label}
              {sortBy === key && (sortDir === "asc" ? " ↑" : " ↓")}
            </button>
          ))}
        </div>
      </div>

      {/* Results count */}
      <p className="text-sm text-subtext0" aria-live="polite" aria-atomic="true">
        {isFiltering ? "Filtering..." : `${result.totalCount} schools`}
      </p>

      {/* AI filter undo banner */}
      {previousFilters && (
        <div
          className="flex items-center gap-3 px-4 py-2 bg-primary/10 border border-primary/20 rounded-lg text-sm transition-all duration-300 ease-out"
          style={{ animation: "fadeInUp 0.3s ease-out" }}
        >
          <span className="text-text">AI updated your filters.</span>
          <button
            onClick={undoChatFilters}
            className="text-primary font-medium hover:underline transition-all duration-150 transform hover:scale-105 active:scale-95"
          >
            Undo
          </button>
        </div>
      )}

      {/* Chart toggle */}
      <div className="flex items-center justify-between">
        <button
          onClick={() => setShowChart((v) => !v)}
          className="text-sm px-3 py-1.5 rounded-lg bg-surface0 text-text hover:bg-surface1 transition-all duration-150 ease-out transform hover:scale-105 active:scale-95"
          style={{ transitionTimingFunction: "cubic-bezier(0.4, 0, 0.2, 1)" }}
        >
          {showChart ? "Hide Chart" : "Show ROI Chart"}
        </button>
      </div>
      {showChart && (
        <div
          className="bg-mantle rounded-lg border border-surface0 p-4 transition-all duration-300 ease-out"
          style={{ animation: "fadeInUp 0.3s ease-out" }}
        >
          <h2 className="text-sm font-bold text-subtext0 mb-4">
            Tuition vs Median Earnings — top 15 matching schools
          </h2>
          <ROIChart schools={paginated} />
        </div>
      )}

      {/* School list or empty state */}
      {paginated.length === 0 ? (
        <div className="text-center py-12">
          <p className="text-xl font-bold text-text mb-2">No schools found</p>
          <p className="text-subtext0 mb-4">
            {hasActiveFilters
              ? "Try adjusting your filters or search terms."
              : "No schools match the current criteria."}
          </p>
          {hasActiveFilters && (
            <button
              onClick={clearAllFilters}
              className="px-4 py-2 bg-primary text-on-primary rounded-lg hover:opacity-90 transition-all duration-150 ease-out transform hover:scale-105 active:scale-95 text-sm font-medium"
              style={{ transitionTimingFunction: "cubic-bezier(0.4, 0, 0.2, 1)" }}
            >
              Clear all filters
            </button>
          )}
        </div>
      ) : (
        /* School cards */
        <div key={listKey} className="space-y-3">
          {paginated.map((school, index) => {
            const payback = calculatePaybackYears(school);
            return (
              <Link
                key={school.slug}
                href={`/school/${school.slug}`}
                className="
                  block p-5 bg-mantle rounded-lg border border-surface0
                  hover:border-primary hover:shadow-[0_0_0_1px_var(--ctp-primary)]
                  hover:-translate-y-0.5 active:translate-y-0
                  transition-all duration-200 ease-out
                  transform hover:scale-[1.005] active:scale-[0.995]
                "
                style={{
                  transitionTimingFunction: "cubic-bezier(0.4, 0, 0.2, 1)",
                  animationDelay: `${index * 30}ms`,
                  animation: `fadeInUp 0.3s ease-out ${index * 30}ms both`,
                }}
              >
                <div className="flex items-start gap-4">
                  <SchoolLogo website={school.website} name={school.name} size={48} />
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 mb-1">
                      <span className="text-primary font-mono text-sm font-bold">
                        {school[activeRankField] ? `#${school[activeRankField]}` : "—"}
                      </span>
                      <span className="font-semibold text-lg truncate">{school.name}</span>
                    </div>
                    <p className="text-subtext0 text-sm">
                      {school.city}, {school.state} · {school.region}
                    </p>
                    {/* Mobile: heart + compare */}
                    <div className="sm:hidden flex items-center gap-2 mt-1">
                      <HeartButton slug={school.slug} size="sm" />
                      <CompareButton slug={school.slug} name={school.name} />
                    </div>
                    {/* Mobile: compact stats inline */}
                    <div className="sm:hidden flex gap-3 text-xs text-subtext0 mt-1">
                      <span className="text-peach">{formatCurrency(school.tuitionInState)}</span>
                      <span className="text-green">{formatCurrency(school.medianEarnings6yr)}</span>
                      {payback && <span className="text-blue">{payback.toFixed(1)}yr payback</span>}
                    </div>
                    <div className="flex flex-wrap gap-3 mt-3">
                      <GradeBadge grade={school.nicheGrades.overall} label="Overall" />
                      <GradeBadge grade={school.nicheGrades.academics} label="Academics" />
                      <GradeBadge grade={school.nicheGrades.campusFood} label="Food" />
                      <GradeBadge grade={school.nicheGrades.partyScene} label="Party" />
                      <GradeBadge grade={school.nicheGrades.studentLife} label="Social" />
                      <GradeBadge grade={school.nicheGrades.safety} label="Safety" />
                    </div>
                  </div>
                  {/* Desktop: stacked right-aligned stats */}
                  <div className="hidden sm:block text-right text-sm space-y-1 shrink-0">
                    <div className="flex justify-end gap-2 mb-1">
                      <CompareButton slug={school.slug} name={school.name} />
                      <HeartButton slug={school.slug} size="sm" />
                    </div>
                    <div>
                      <span className="text-subtext0">In-state: </span>
                      <span className="font-medium text-peach">{formatCurrency(school.tuitionInState)}</span>
                    </div>
                    <div>
                      <span className="text-subtext0">Out-of-state: </span>
                      <span className="font-medium text-peach">{formatCurrency(school.tuitionOutOfState)}</span>
                    </div>
                    <div>
                      <span className="text-subtext0">Earnings: </span>
                      <span className="font-medium text-green">
                        {formatCurrency(school.medianEarnings6yr)}
                      </span>
                    </div>
                    <div>
                      <span className="text-subtext0">Accept: </span>
                      <span className="font-medium">{formatPercent(school.acceptanceRate)}</span>
                    </div>
                    {payback && (
                      <div>
                        <span className="text-subtext0">Payback: </span>
                        <span className="font-medium text-blue">{payback.toFixed(1)}yr</span>
                      </div>
                    )}
                  </div>
                </div>
              </Link>
            );
          })}
        </div>
      )}

      {/* Pagination */}
      {result.totalCount > 0 && (
        <Pagination
          currentPage={page}
          totalPages={totalPages}
          onPageChange={(p) => {
            setPage(p);
            window.scrollTo({ top: 0, behavior: "smooth" });
          }}
        />
      )}
    </div>
  );
}

"use client";

import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  Legend,
} from "recharts";
import type { School } from "@/lib/data/schema";

interface ROIChartProps {
  schools: School[];
}

export default function ROIChart({ schools }: ROIChartProps) {
  const data = schools
    .filter((s) => s.medianEarnings6yr != null && s.medianEarnings6yr > 0)
    .slice(0, 15)
    .map((s) => ({
      name: s.name.length > 20 ? s.name.slice(0, 20) + "..." : s.name,
      inStateTuition: s.tuitionInState,
      outOfStateTuition: s.tuitionOutOfState,
      earnings: s.medianEarnings6yr as number,
    }));

  if (data.length === 0) {
    return (
      <div className="w-full h-[400px] flex items-center justify-center bg-mantle rounded-lg border border-surface0">
        <div className="text-center text-subtext0">
          <p className="text-lg font-bold text-overlay0 mb-2">No Chart Data</p>
          <p className="text-sm">No data available for chart</p>
        </div>
      </div>
    );
  }

  return (
    <div className="w-full h-[480px]">
      <ResponsiveContainer width="100%" height="100%">
        <BarChart data={data} margin={{ top: 20, right: 30, left: 20, bottom: 80 }}>
          <CartesianGrid strokeDasharray="3 3" stroke="var(--ctp-surface1)" />
          <XAxis
            dataKey="name"
            angle={-45}
            textAnchor="end"
            interval={0}
            height={100}
            tick={{ fontSize: 10, fill: "var(--ctp-subtext0)" }}
          />
          <YAxis
            tick={{ fill: "var(--ctp-subtext0)" }}
            tickFormatter={(v) => `$${(v / 1000).toFixed(0)}k`}
          />
          <Tooltip
            contentStyle={{
              backgroundColor: "var(--ctp-mantle)",
              border: "1px solid var(--ctp-surface0)",
              color: "var(--ctp-text)",
            }}
            formatter={(value: number) => [`$${value.toLocaleString()}`, ""]}
          />
          <Legend verticalAlign="top" height={36} />
          <Bar dataKey="inStateTuition" name="In-State Tuition" fill="var(--ctp-peach)" />
          <Bar dataKey="outOfStateTuition" name="Out-of-State Tuition" fill="var(--ctp-red)" />
          <Bar dataKey="earnings" name="Median Earnings (6yr)" fill="var(--ctp-green)" />
        </BarChart>
      </ResponsiveContainer>
    </div>
  );
}

