import type { Metadata } from "next";
import ResourceCard from "./ResourceCard";
import { resourceCategories } from "./data";
import PageTransition from "@/components/PageTransition";

export const metadata: Metadata = { title: "Resources" };

export default function ResourcesPage() {
  return (
    <PageTransition>
      <div id="main-content" className="py-8">
        <section className="mb-12">
          <h1 className="text-3xl font-bold mb-4">Resources for New Developers</h1>
          <p className="text-lg text-subtext0 max-w-2xl">
            Curated tools, tutorials, and guides to help you learn to code, ace interviews, and
            launch your career in computer science.
          </p>
        </section>

        {resourceCategories.map((category) => (
          <section key={category.title} className="mb-12">
            <h2 className="text-2xl font-bold mb-6">{category.title}</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              {category.resources.map((resource) => (
                <ResourceCard
                  key={resource.name}
                  name={resource.name}
                  url={resource.url}
                  description={resource.description}
                />
              ))}
            </div>
          </section>
        ))}
      </div>
    </PageTransition>
  );
}

"use client";

import Link from "next/link";
import { useState, useEffect } from "react";
import { useCompareContext } from "@/components/CompareProvider";

export default function CompareBar() {
  const { slugs, names, remove, clear } = useCompareContext();
  const [mounted, setMounted] = useState(false);
  // eslint-disable-next-line react-hooks/set-state-in-effect
  useEffect(() => setMounted(true), []);

  if (!mounted || slugs.length === 0) return null;

  const compareUrl = `/compare?schools=${slugs.join(",")}`;

  return (
    <div className="fixed bottom-0 left-0 right-0 z-50 bg-mantle border-t border-surface0 shadow-2xl px-4 py-3 flex items-center justify-between gap-4">
      <div className="flex items-center gap-2 flex-wrap min-w-0">
        <span className="text-subtext0 text-sm font-medium shrink-0">Compare:</span>
        {slugs.map((slug) => (
          <span
            key={slug}
            className="flex items-center gap-1 px-2 py-0.5 bg-surface0 rounded-full text-sm text-text"
          >
            <span className="max-w-[140px] truncate">{names[slug] ?? slug}</span>
            <button
              type="button"
              onClick={() => remove(slug)}
              aria-label={`Remove ${names[slug] ?? slug} from comparison`}
              className="text-subtext0 hover:text-red transition-colors ml-0.5"
            >
              <svg
                width="12"
                height="12"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth="2.5"
                aria-hidden="true"
              >
                <line x1="18" y1="6" x2="6" y2="18" />
                <line x1="6" y1="6" x2="18" y2="18" />
              </svg>
            </button>
          </span>
        ))}
      </div>
      <div className="flex items-center gap-3 shrink-0">
        <button
          type="button"
          onClick={clear}
          className="text-sm text-subtext0 hover:text-text transition-colors"
        >
          Clear
        </button>
        <Link
          href={compareUrl}
          className="px-4 py-2 bg-primary text-on-primary rounded-lg text-sm font-medium hover:opacity-90 transition-opacity whitespace-nowrap"
        >
          Compare {slugs.length} school{slugs.length !== 1 ? "s" : ""}
        </Link>
      </div>
    </div>
  );
}

